import { initializeApp } from "https://www.gstatic.com/firebasejs/10.12.0/firebase-app.js";
import { getFirestore } from "https://www.gstatic.com/firebasejs/10.12.0/firebase-firestore.js";
import { getStorage, ref, uploadBytes, getDownloadURL } from "https://www.gstatic.com/firebasejs/10.12.0/firebase-storage.js";
import { getAuth, signInAnonymously } from "https://www.gstatic.com/firebasejs/10.12.0/firebase-auth.js";

let app, db, storage, auth;

export async function initFirebase() {
    try {
        // Fetch config generated by Firebase Hosting
        const response = await fetch('/__/firebase/init.json');
        if (!response.ok) {
            throw new Error(`Failed to load Firebase config: ${response.statusText}`);
        }
        const config = await response.json();
        
        app = initializeApp(config);
        db = getFirestore(app);
        storage = getStorage(app);
        auth = getAuth(app);
        
        // Sign in anonymously for easy dev setup (later can use custom token with Line login if backend is added, 
        // but for now anonymous auth + Line ID stored in db is the simplest)
        await signInAnonymously(auth);
        
        console.log("Firebase initialized (Modular SDK v10)");
        return { app, db, storage, auth };
    } catch (e) {
        console.error("Firebase init error (if running locally without emulator/hosting, this will fail):", e);
        // Fallback or mock could be implemented here for local file:// testing
        throw e;
    }
}

export function getDb() { return db; }
export function getStorageInstance() { return storage; }
export function getAuthInstance() { return auth; }

/**
 * Compress image before uploading to save Firebase Storage quota
 * @param {File} imageFile 
 * @returns {Promise<File>} Compressed File
 */
export async function compressImage(imageFile) {
    if (!window.imageCompression) {
        console.warn("browser-image-compression not loaded, returning original file");
        return imageFile;
    }
    
    console.log(`Original file size: ${imageFile.size / 1024 / 1024} MB`);
    const options = {
        maxSizeMB: 0.15, // Max 150KB as requested by user
        maxWidthOrHeight: 1280,
        useWebWorker: true,
        initialQuality: 0.7
    };

    try {
        const compressedFile = await window.imageCompression(imageFile, options);
        console.log(`Compressed file size: ${compressedFile.size / 1024 / 1024} MB`);
        return compressedFile;
    } catch (error) {
        console.error("Image compression error:", error);
        return imageFile; // fallback to original
    }
}

/**
 * Upload an image file to Firebase Storage
 * @param {File} file - The compressed image file
 * @param {string} path - Storage path (e.g. families/{familyId}/photos/{filename})
 * @returns {Promise<string>} Download URL
 */
export async function uploadPhoto(file, path) {
    if (!storage) throw new Error("Firebase not initialized");
    const storageRef = ref(storage, path);
    await uploadBytes(storageRef, file);
    return await getDownloadURL(storageRef);
}
